import ray

def main():
    # Connect to the Ray cluster using the specific port to avoid SkyPilot's internal Ray
    ray.init(address='127.0.0.1:6379')

    @ray.remote
    def simple_task():
        return 'ray task complete'

    # Run the remote function and get the result
    result = ray.get(simple_task.remote())
    print(result)

if __name__ == "__main__":
    main()
